import numpy as npimport itertoolsimport pylab as pfrom lingam import CAMUVfrom tigramite.independence_tests.gpdc import GPDCfrom tigramite.independence_tests.cmiknn import CMIknnfrom tigramite.independence_tests.parcorr import ParCorrimport networkx as netdef findsubsets(s, n):    return list(itertools.combinations(s, n))class CAMUV_extended(CAMUV):    def __init__(            self, alpha=0.01, num_explanatory_vals=2,            max_regress_size = 2,            independence="hsic", ind_corr=0.5, CI_test = "CMIknn" #GP, ParCorr    ):        super().__init__(alpha, num_explanatory_vals, independence, ind_corr)        # Check parameters        if max_regress_size <= 0:            raise ValueError("max_regress_size must be > 0.")        self._max_regress_size = max_regress_size        self._adjacency_matrix = None        self._ancestor = None        self._not_ancestor = None        self._possible_child = None        self._CI_test = CI_test    def fit_extended(self,X,adj_mat,message = False):        # X: data matrix        # adj_mat: result of CAM-UV        n = X.shape[0]        p = adj_mat.shape[0]        self._adjacency_matrix = adj_mat        # set diagonal elements to 0        for i in range(p): self._adjacency_matrix[i,i] = 0        self._ancestor = [set()] * p        self._not_ancestor = [set()] * p        self._possible_child = [None] * p        self._visible_mat = np.zeros_like(self._adjacency_matrix)        for i in range(p): self._possible_child[i] = list()        mat = self._adjacency_matrix.copy()        mat_new = mat.copy()        # checkVisible: checking each NaN location        nan_loc = np.where(np.isnan(mat))        nan_num = len(nan_loc[0])        for i in range(nan_num):            x_i = nan_loc[0][i]            nan_x_i = nan_loc[1][nan_loc[0] == x_i]            for j in range(nan_x_i.shape[0]):                # consider the nan edge between x_i and x_j                x_j = nan_x_i[j]                nan_x_j = nan_loc[0][nan_loc[1] == x_j]                candidate_i = set(nan_x_i) - {x_j} - {x_i}                candidate_j = set(nan_x_j) - {x_i} - {x_j}                candidate_all = candidate_i.union(candidate_j)                # get the parents of x_i and x_j                P_i = set(np.where(mat_new[x_i, :] == 1)[0])                P_j = set(np.where(mat_new[x_j, :] == 1)[0])                Q = candidate_all.union(P_i,P_j)                iNotParent = False                jNotParent = False                isNonEdge = False                for size_i in range(1,min(self._max_regress_size,len(Q)) + 1):                    if isNonEdge: break                    search_i = findsubsets(Q,size_i)                    for s_1 in search_i:                        if isNonEdge: break                        for size_j in range(1, min(self._max_regress_size, len(Q)) + 1):                            if isNonEdge: break                            search_j = findsubsets(Q,size_j)                            for s_2 in search_j:                                if isNonEdge: break                                explaining_i_1 = set(s_1)                                explaining_j_1 = set(s_2)                                residual_i_1 = self._get_residual(X, x_i, explaining_i_1)                                residual_j_1 = self._get_residual(X, x_j, explaining_j_1)                                in_X_1 = np.reshape(residual_i_1, [n, 1])                                in_Y_1 = np.reshape(residual_j_1, [n, 1])                                if self._is_independent(in_X_1, in_Y_1):                                    # visible non-edge                                    mat_new[x_i, x_j] = 0                                    mat_new[x_j, x_i] = 0                                    isNonEdge = True                                    break                                else:                                    explaining_i_2 = explaining_i_1  | {x_j}                                    residual_i_2 = self._get_residual(X, x_i, explaining_i_2)                                    in_X_2 = np.reshape(residual_i_2, [n, 1])                                    if self._is_independent(in_X_2, in_Y_1):                                        iNotParent = True                                    explaining_j_2 = explaining_j_1 | {x_i}                                    residual_j_2 = self._get_residual(X, x_j, explaining_j_2)                                    in_Y_2 = np.reshape(residual_j_2, [n, 1])                                    if self._is_independent(in_X_1, in_Y_2):                                        jNotParent = True                                    if iNotParent & jNotParent:                                        #visible non-edge                                        mat_new[x_i, x_j] = 0                                        mat_new[x_j, x_i] = 0                                        isNonEdge = True                                        break                if (not isNonEdge) and iNotParent:                    mat_new[x_i, x_j] = 1; mat_new[x_j, x_i] = 0                if (not isNonEdge) and jNotParent:                    mat_new[x_j, x_i] = 1; mat_new[x_i, x_j] = 0        # end of checkVisible        # end of converting NaN to 0/1        mat = mat_new.copy()        self._adjacency_matrix = mat.copy()        self._visible_mat = mat.copy()        # start of checkOnPath        #starting to check each visible pair:        for i in range(p):            for j in range(0,i):                if (not np.isnan(mat[i,j])) and (not np.isnan(mat[j,i])): # visible pair                    for k in range(p):                        if (k != i) and (k != j):                            if np.isnan(mat[i,k]) or np.isnan(mat[j,k]): # relation of x_k to x_i, x_j is not determined                                # list up all subsets that:                                # * do not contain x_k                                # contains parents of x_i or parents of x_j or nodes where the relation is not clear                                # contain no other nodes                                i_nan = set(np.where(np.isnan(mat[i,:]))[0])                                j_nan = set(np.where(np.isnan(mat[j,:]))[0])                                P_i = set(np.where(mat_new[i, :] == 1)[0])                                P_j = set(np.where(mat_new[j, :] == 1)[0])                                candidate = i_nan | j_nan | P_i | P_j - {k}                                candidate_for_i = candidate | {j}                                candidate_for_j = candidate | {i}                                isOnPath = True                                for sub_size_i in range(1,min(self._max_regress_size,len(candidate_for_i)) + 1):                                    if not isOnPath:                                        break                                    sub_set_i = findsubsets(candidate_for_i, sub_size_i)                                    for explain_i in sub_set_i:                                        if not isOnPath:                                            break                                        for sub_size_j in range(1, min(self._max_regress_size, len(candidate_for_j)) + 1):                                            if not isOnPath:                                                break                                            sub_set_j = findsubsets(candidate_for_j, sub_size_j)                                            for explain_j in sub_set_j:                                                if not isOnPath: break                                                residual_i = self._get_residual(X, i, explain_i)                                                in_X = np.reshape(residual_i, [n, 1])                                                residual_j = self._get_residual(X, j, explain_j)                                                in_Y = np.reshape(residual_j, [n, 1])                                                if self._is_independent(in_X, in_Y):                                                    isOnPath = False                                                    break                                if isOnPath:                                    self._possible_child[k].append([i, j])                                    if mat_new[i,j] == 1:                                        self._ancestor[i].add(k)                                        self._not_ancestor[k].add(i)                                        mat_new[k,i] = 0                                    else:                                        if mat_new[j,i] == 1:                                            self._ancestor[j].add(k)                                            self._not_ancestor[k].add(j)                                            mat_new[k,j] = 0        mat = mat_new.copy()        self._adjacency_matrix = mat.copy()        # end of checkOnPath        #process the possible_child to find more ancestors:        self._process_possible_child()        nan_loc = np.where(np.isnan(mat))        nan_num = len(nan_loc[0])        for i in range(nan_num):            x_i = nan_loc[0][i]            nan_x_i = nan_loc[1][nan_loc[0] == x_i]            for j in range(nan_x_i.shape[0]):                x_j = nan_x_i[j]                # x_k: ancestor of x_i, excluding x_i                ancestor_x_i_list = self._find_ancestor(x_i) - {x_i} - {x_j}                for x_k in ancestor_x_i_list:                    # testing x_k and x_i, conditioning on x_j                    data_test = X[:,[x_k,x_i,x_j]].T                    p_value = 0                    if self._CI_test == "GP":                        gpdc = GPDC(significance='analytic', gp_params=None)                        value = gpdc.get_dependence_measure(array=data_test, xyz=np.array([0, 1, 2]))                        # T: number of samples                        # dim: number of dimensions in X , Y | Z. In our case, dim = 3                        p_value = gpdc.get_analytic_significance(value=value, T=n, dim=3,                                                                 xyz=np.array([0, 1, 2]))                    elif self._CI_test == "CMIknn":                        my_test = CMIknn()                        value = my_test.get_dependence_measure(array=data_test, xyz=np.array([0, 1, 2]))                        p_value = my_test.get_shuffle_significance(value=value, array=data_test,                                                                   xyz=np.array([0, 1, 2]))                    elif self._CI_test == "ParCorr":                        my_test = ParCorr()                        value = my_test.get_dependence_measure(array=data_test, xyz=np.array([0, 1, 2]))                        p_value = my_test.get_analytic_significance(value=value, T=n, dim=3,                                                                    xyz=np.array([0, 1, 2]))                    if p_value >= self._alpha:                        # independent                        if x_j not in self._not_ancestor[x_i]:                            if message:                                print("Not_Ancestor by CI!")                            self._not_ancestor[x_i].add(x_j)                            if self._adjacency_matrix[x_i,x_j] == 1:                                if message:                                    print("Conflict between I and CI")                                self._adjacency_matrix[x_i, x_j] = 0                                            #do nothing in this case                            else:                                self._adjacency_matrix[x_i,x_j] = 0                                self._ancestor[x_j].add(x_i)                                if message:                                    print("Ancestor by CI!")                                    break        # process the possible_child to find more ancestors:        isChange = True        while (isChange):            # combine possible_child and ancestor to determine parentships            isChange = self._combine_ancestor_possible_child()        return self    def _process_possible_child(self):        mat_temp = self._adjacency_matrix.copy()        mat_temp[np.isnan(mat_temp)] = 0        g = net.DiGraph(mat_temp.T)        for j in range(len(self._possible_child)):            len_j = len(self._possible_child[j])            if len_j > 0:                for i in range(len_j):                    first_node = self._possible_child[j][i][0]                    second_node = self._possible_child[j][i][1]                    descendant_of_first  = net.descendants(g,first_node) | {first_node}                    descendant_of_second =  net.descendants(g,second_node) | {second_node}                    common = descendant_of_second.intersection(descendant_of_first)                    for temp in common:                        self._ancestor[temp].add(j)                        self._not_ancestor[j].add(temp)                        self._adjacency_matrix[j,temp] = 0    def _find_ancestor(self, x_i):        mat_temp_2 = self._adjacency_matrix.copy()        mat_temp_2[np.isnan(mat_temp_2)] = 0        g = net.DiGraph(mat_temp_2.T)        return net.ancestors(g,x_i) | self._ancestor[x_i] | {x_i}    def _combine_ancestor_possible_child(self):        isChange = False        mat_temp = self._adjacency_matrix.copy()        mat_temp[np.isnan(mat_temp)] = 0        g = net.DiGraph(mat_temp.T)        for i in range(len(self._possible_child)):            len_i = len(self._possible_child[i])            for j in range(len_i):                first_node = self._possible_child[i][j][0]                second_node = self._possible_child[i][j][1]                if first_node == second_node:                    continue                descendant_of_first = net.descendants(g, first_node) | {first_node}                if i in descendant_of_first:                    self._ancestor[i].add(first_node)                    self._not_ancestor[first_node].add(i)                    self._adjacency_matrix[first_node, i] = 0                descendant_of_second = net.descendants(g, second_node) | {second_node}                if i in descendant_of_second:                    self._ancestor[i].add(second_node)                    self._not_ancestor[second_node].add(i)                    self._adjacency_matrix[second_node, i] = 0                if (first_node in self._ancestor[i] or self._adjacency_matrix[first_node,i] == 0) and (np.isnan(self._adjacency_matrix[second_node,i])) :                    # then there is no edge from i -> first_node                        print("parent identified by I and CI!")                        self._adjacency_matrix[first_node,i]   = 0                        self._adjacency_matrix[second_node,i]  = 1                        self._adjacency_matrix[i, second_node] = 0                        isChange = True                elif (second_node in self._ancestor[i] or self._adjacency_matrix[second_node,i] == 0) and np.isnan(self._adjacency_matrix[first_node,i]):                        print("parent identified by I and CI!")                        self._adjacency_matrix[second_node,i] = 0                        self._adjacency_matrix[first_node,i] = 1                        self._adjacency_matrix[i, first_node] = 0                        isChange = True        return isChange